        if(s.has('Interscapular pain')) score+=1;
        if(a.has('Prolonged sitting')||a.has('End-range movements')||a.has('Trunk rotation')) score+=3;
        if(a.has('Extension')||a.has('Activities requiring upright posture')) score+=1;
