  state.symptoms = new Set();
  state.symptomText = '';
  state.agg = new Set();
  state.aggText = '';
  state.alle = new Set();
  state.alleText = '';
  state.objective = {};
  state.specialTests = {};
  state._rfFlagged = new Set();
  const ageEl = document.getElementById('patientAge');
